// generateSecureFilename creates a cryptographically random filename with the given extension.
func generateSecureFilename(ext string) (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes) + ext, nil
}

// containsDangerousPattern checks if a filename contains path traversal or other dangerous patterns.
func containsDangerousPattern(name string) bool {
	for _, pattern := range dangerousPatterns {
		if strings.Contains(name, pattern) {
			return true
		}
	}
	// Also reject absolute paths.
	if filepath.IsAbs(name) {
		return true
	}
	// Reject null bytes.
	if strings.ContainsRune(name, 0) {
		return true
	}
	return false
}